import {
  appendShoppingAuditEntry,
  flushShoppingAuditLog,
} from "./shopping-audit-log.mjs";

export const ASKET_RETAILER = "Asket";
export const ASKET_BASE_PRODUCT_URL = "https://www.asket.com/products";
export const ASKET_CART_STAGING_STATUSES = Object.freeze([
  "success",
  "out_of_stock",
  "login_expired",
  "error",
]);

export function createAsketProductUrl(productId, baseProductUrl = ASKET_BASE_PRODUCT_URL) {
  const normalizedProductId = normalizeNonEmptyString(productId, "productId");
  return `${baseProductUrl.replace(/\/+$/, "")}/${encodeURIComponent(normalizedProductId)}`;
}

export function createAsketCartStagingSelectors(size) {
  const normalizedSize = normalizeNonEmptyString(size, "size");
  const quotedSize = JSON.stringify(normalizedSize);

  return {
    loginExpired: [
      "form[action*='login']",
      "form[action*='account']",
      "text=/log in/i",
      "text=/sign in/i",
      "text=/session expired/i",
    ],
    outOfStock: [
      "text=/out of stock/i",
      "text=/sold out/i",
      "button:has-text(\"Sold out\")",
      "button:has-text(\"Out of stock\")",
    ],
    size: [
      `button:has-text(${quotedSize})`,
      `[data-testid*="size"] button:has-text(${quotedSize})`,
      `[aria-label=${quotedSize}]`,
      `input[name="size"][value=${quotedSize}]`,
    ],
    addToCart: [
      "button:has-text(\"Add to bag\")",
      "button:has-text(\"Add to cart\")",
      "button:has-text(\"Add\")",
      "[data-testid*='add-to-cart']",
      "[data-testid*='add-to-bag']",
    ],
  };
}

export async function stageAsketCartItem({
  page,
  productUrl,
  productId,
  size,
  auditLogPath,
  audit = appendShoppingAuditEntry,
  flushAudit = flushShoppingAuditLog,
  selectors = createAsketCartStagingSelectors(size),
  navigationWaitUntil = "domcontentloaded",
} = {}) {
  validatePage(page);
  const normalizedSize = normalizeNonEmptyString(size, "size");
  const resolvedProductUrl =
    productUrl === undefined
      ? createAsketProductUrl(productId)
      : normalizeUrl(productUrl, "productUrl");

  const resultBase = {
    productUrl: resolvedProductUrl,
    retailer: ASKET_RETAILER,
    size: normalizedSize,
  };

  if (productId !== undefined) {
    resultBase.productId = normalizeNonEmptyString(productId, "productId");
  }

  let activeActionType = "cart_add";

  try {
    activeActionType = "page_read";
    auditStep(audit, auditLogPath, "page_read", "started");
    await page.goto(resolvedProductUrl, { waitUntil: navigationWaitUntil });

    if (await hasVisibleLocator(page, selectors.loginExpired)) {
      auditStep(audit, auditLogPath, "page_read", "failed");
      return {
        ...resultBase,
        reason: "Asket login session appears to be expired.",
        status: "login_expired",
      };
    }

    auditStep(audit, auditLogPath, "page_read", "succeeded");

    activeActionType = "size_select";
    auditStep(audit, auditLogPath, "size_select", "started");
    await clickFirstAvailableLocator(page, selectors.size, `size ${normalizedSize}`);
    auditStep(audit, auditLogPath, "size_select", "succeeded");

    activeActionType = "cart_add";
    auditStep(audit, auditLogPath, "cart_add", "started");
    if (await hasVisibleLocator(page, selectors.outOfStock)) {
      auditStep(audit, auditLogPath, "cart_add", "failed");
      return {
        ...resultBase,
        reason: "Selected Asket size is out of stock.",
        status: "out_of_stock",
      };
    }

    const addToCartLocator = await findFirstVisibleLocator(page, selectors.addToCart);
    if (!addToCartLocator) {
      throw new Error("Could not find an Asket add-to-cart button.");
    }
    if (!(await locatorIsEnabled(addToCartLocator))) {
      auditStep(audit, auditLogPath, "cart_add", "failed");
      return {
        ...resultBase,
        reason: "Selected Asket size is out of stock.",
        status: "out_of_stock",
      };
    }

    await addToCartLocator.click();

    if (await hasVisibleLocator(page, selectors.loginExpired)) {
      auditStep(audit, auditLogPath, "cart_add", "failed");
      return {
        ...resultBase,
        reason: "Asket login session expired before cart add completed.",
        status: "login_expired",
      };
    }

    auditStep(audit, auditLogPath, "cart_add", "succeeded");
    return {
      ...resultBase,
      status: "success",
    };
  } catch (err) {
    auditStep(audit, auditLogPath, activeActionType, "failed");
    return {
      ...resultBase,
      error: err instanceof Error ? err.message : String(err),
      status: "error",
    };
  } finally {
    if (typeof flushAudit === "function") {
      await flushAudit();
    }
  }
}

function auditStep(audit, auditLogPath, actionType, status) {
  if (typeof audit !== "function") {
    return;
  }

  audit(
    {
      actionType,
      retailer: ASKET_RETAILER,
      status,
    },
    auditLogPath,
  );
}

async function clickFirstAvailableLocator(page, selectors, description) {
  for (const selector of normalizeSelectors(selectors)) {
    const locator = firstLocator(page, selector);
    if ((await locatorHasMatches(locator)) && (await locatorIsVisible(locator))) {
      if (!(await locatorIsEnabled(locator))) {
        continue;
      }
      await locator.click();
      return selector;
    }
  }

  throw new Error(`Could not find an enabled Asket ${description}.`);
}

async function hasVisibleLocator(page, selectors) {
  return Boolean(await findFirstVisibleLocator(page, selectors));
}

async function findFirstVisibleLocator(page, selectors) {
  for (const selector of normalizeSelectors(selectors)) {
    const locator = firstLocator(page, selector);
    if ((await locatorHasMatches(locator)) && (await locatorIsVisible(locator))) {
      return locator;
    }
  }
  return undefined;
}

function firstLocator(page, selector) {
  const locator = page.locator(selector);
  return locator.first?.() ?? locator;
}

async function locatorHasMatches(locator) {
  if (typeof locator.count === "function") {
    return (await locator.count()) > 0;
  }
  return true;
}

async function locatorIsVisible(locator) {
  if (typeof locator.isVisible === "function") {
    return locator.isVisible();
  }
  return true;
}

async function locatorIsEnabled(locator) {
  if (typeof locator.isEnabled === "function") {
    return locator.isEnabled();
  }
  return true;
}

function validatePage(page) {
  if (!page || typeof page.goto !== "function" || typeof page.locator !== "function") {
    throw new TypeError("page must provide Playwright-compatible goto and locator methods.");
  }
}

function normalizeSelectors(selectors) {
  if (!Array.isArray(selectors) || selectors.length === 0) {
    throw new TypeError("selectors must be a non-empty array.");
  }
  return selectors.map((selector) => normalizeNonEmptyString(selector, "selector"));
}

function normalizeNonEmptyString(value, field) {
  if (typeof value !== "string" || !value.trim()) {
    throw new TypeError(`${field} must be a non-empty string.`);
  }
  return value.trim();
}

function normalizeUrl(value, field) {
  const normalized = normalizeNonEmptyString(value, field);
  try {
    return new URL(normalized).toString();
  } catch {
    throw new TypeError(`${field} must be a valid URL.`);
  }
}

import { mkdtemp, rm } from "node:fs/promises";
import { join } from "node:path";
import { tmpdir } from "node:os";
import test from "node:test";
import assert from "node:assert/strict";

import {
  createAsketCartStagingSelectors,
  createAsketProductUrl,
  stageAsketCartItem,
} from "../src/asket-cart-staging-recipe.mjs";
import { readShoppingAuditLog } from "../src/shopping-audit-log.mjs";

test("creates an Asket product URL from a product id", () => {
  assert.equal(
    createAsketProductUrl("the-overshirt"),
    "https://www.asket.com/products/the-overshirt",
  );
});

test("navigates, selects the requested size, adds to cart, and audits each step", async () => {
  const dir = await mkdtemp(join(tmpdir(), "asket-cart-staging-"));
  const auditPath = join(dir, "audit.jsonl");
  const selectors = createAsketCartStagingSelectors("M");
  const page = new FakePage({
    locators: {
      [selectors.size[0]]: { visible: true },
      [selectors.addToCart[0]]: { visible: true },
    },
  });

  try {
    const result = await stageAsketCartItem({
      auditLogPath: auditPath,
      page,
      productUrl: "https://www.asket.com/products/the-t-shirt",
      selectors,
      size: "M",
    });
    const auditEntries = await readShoppingAuditLog(auditPath);

    assert.equal(result.status, "success");
    assert.deepEqual(page.events, [
      ["goto", "https://www.asket.com/products/the-t-shirt"],
      ["click", selectors.size[0]],
      ["click", selectors.addToCart[0]],
    ]);
    assert.deepEqual(
      auditEntries.map((entry) => [entry.actionType, entry.status, entry.retailer]),
      [
        ["page_read", "started", "Asket"],
        ["page_read", "succeeded", "Asket"],
        ["size_select", "started", "Asket"],
        ["size_select", "succeeded", "Asket"],
        ["cart_add", "started", "Asket"],
        ["cart_add", "succeeded", "Asket"],
      ],
    );
  } finally {
    await rm(dir, { recursive: true, force: true });
  }
});

test("returns out_of_stock when the selected size cannot be added", async () => {
  const selectors = createAsketCartStagingSelectors("XL");
  const page = new FakePage({
    locators: {
      [selectors.size[0]]: { visible: true },
      [selectors.outOfStock[0]]: { visible: true },
      [selectors.addToCart[0]]: { visible: true },
    },
  });

  const result = await stageAsketCartItem({
    audit: captureAudit(),
    flushAudit: undefined,
    page,
    productId: "the-overshirt",
    selectors,
    size: "XL",
  });

  assert.equal(result.status, "out_of_stock");
  assert.equal(result.productUrl, "https://www.asket.com/products/the-overshirt");
  assert.deepEqual(page.events, [
    ["goto", "https://www.asket.com/products/the-overshirt"],
    ["click", selectors.size[0]],
  ]);
});

test("returns out_of_stock when the add-to-cart control is disabled", async () => {
  const selectors = createAsketCartStagingSelectors("L");
  const page = new FakePage({
    locators: {
      [selectors.size[0]]: { visible: true },
      [selectors.addToCart[0]]: { enabled: false, visible: true },
    },
  });

  const result = await stageAsketCartItem({
    audit: captureAudit(),
    flushAudit: undefined,
    page,
    productUrl: "https://www.asket.com/products/the-shirt",
    selectors,
    size: "L",
  });

  assert.equal(result.status, "out_of_stock");
  assert.deepEqual(page.events, [
    ["goto", "https://www.asket.com/products/the-shirt"],
    ["click", selectors.size[0]],
  ]);
});

test("returns login_expired before size selection when Asket redirects to login", async () => {
  const selectors = createAsketCartStagingSelectors("S");
  const page = new FakePage({
    locators: {
      [selectors.loginExpired[0]]: { visible: true },
      [selectors.size[0]]: { visible: true },
    },
  });
  const audits = [];

  const result = await stageAsketCartItem({
    audit: captureAudit(audits),
    flushAudit: undefined,
    page,
    productUrl: "https://www.asket.com/products/the-shirt",
    selectors,
    size: "S",
  });

  assert.equal(result.status, "login_expired");
  assert.deepEqual(page.events, [["goto", "https://www.asket.com/products/the-shirt"]]);
  assert.deepEqual(
    audits.map((entry) => [entry.actionType, entry.status]),
    [
      ["page_read", "started"],
      ["page_read", "failed"],
    ],
  );
});

test("returns error when the requested size control is missing", async () => {
  const selectors = createAsketCartStagingSelectors("XS");
  const page = new FakePage();
  const audits = [];

  const result = await stageAsketCartItem({
    audit: captureAudit(audits),
    flushAudit: undefined,
    page,
    productUrl: "https://www.asket.com/products/the-shirt",
    selectors,
    size: "XS",
  });

  assert.equal(result.status, "error");
  assert.match(result.error, /size XS/);
  assert.deepEqual(audits.at(-1), {
    actionType: "size_select",
    retailer: "Asket",
    status: "failed",
  });
});

function captureAudit(target = []) {
  return (entry) => {
    target.push(entry);
  };
}

class FakePage {
  constructor({ locators = {} } = {}) {
    this.events = [];
    this.locators = locators;
  }

  async goto(url) {
    this.events.push(["goto", url]);
  }

  locator(selector) {
    return new FakeLocator({
      events: this.events,
      selector,
      state: this.locators[selector],
    });
  }
}

class FakeLocator {
  constructor({ events, selector, state }) {
    this.events = events;
    this.selector = selector;
    this.state = state;
  }

  first() {
    return this;
  }

  async count() {
    return this.state ? 1 : 0;
  }

  async isVisible() {
    return Boolean(this.state?.visible);
  }

  async isEnabled() {
    return this.state?.enabled !== false;
  }

  async click() {
    this.events.push(["click", this.selector]);
  }
}

import { appendFile, mkdir, readFile } from "node:fs/promises";
import { dirname, resolve } from "node:path";

export const SHOPPING_AUDIT_LOG_SCHEMA_VERSION = 1;
export const DEFAULT_SHOPPING_AUDIT_LOG_PATH = "data/shopping-audit-log.jsonl";
export const SHOPPING_AUDIT_ACTION_TYPES = Object.freeze([
  "search",
  "page_read",
  "size_select",
  "cart_add",
  "cart_peek",
]);
export const SHOPPING_AUDIT_STATUSES = Object.freeze(["started", "succeeded", "failed"]);

let auditWriteQueue = Promise.resolve();

export function createShoppingAuditEntry(entry, now = new Date()) {
  if (!entry || typeof entry !== "object" || Array.isArray(entry)) {
    throw new TypeError("Shopping audit entry must be an object.");
  }

  const normalized = {
    schemaVersion: SHOPPING_AUDIT_LOG_SCHEMA_VERSION,
    actionType: normalizeEnum(entry.actionType, "actionType", SHOPPING_AUDIT_ACTION_TYPES),
    retailer: normalizeString(entry.retailer, "retailer"),
    timestamp: normalizeTimestamp(entry.timestamp ?? now),
    status: normalizeEnum(entry.status, "status", SHOPPING_AUDIT_STATUSES),
  };

  if (entry.screenshotPath !== undefined) {
    normalized.screenshotPath = normalizeString(entry.screenshotPath, "screenshotPath");
  }

  return normalized;
}

export function appendShoppingAuditEntry(
  entry,
  filePath = DEFAULT_SHOPPING_AUDIT_LOG_PATH,
  options = {},
) {
  const normalized = createShoppingAuditEntry(entry, options.now);
  const target = resolve(filePath);

  auditWriteQueue = auditWriteQueue
    .catch(() => undefined)
    .then(async () => {
      await mkdir(dirname(target), { recursive: true });
      await appendFile(target, `${JSON.stringify(normalized)}\n`, "utf8");
    })
    .catch((err) => {
      if (typeof options.onError === "function") {
        options.onError(err);
      }
    });

  return normalized;
}

export async function flushShoppingAuditLog() {
  await auditWriteQueue;
}

export async function readShoppingAuditLog(filePath = DEFAULT_SHOPPING_AUDIT_LOG_PATH) {
  try {
    const raw = await readFile(resolve(filePath), "utf8");
    return raw
      .split("\n")
      .filter(Boolean)
      .map((line) => createShoppingAuditEntry(JSON.parse(line)));
  } catch (err) {
    if (err.code === "ENOENT") {
      return [];
    }
    throw err;
  }
}

function normalizeEnum(value, field, allowedValues) {
  if (!allowedValues.includes(value)) {
    throw new TypeError(`${field} must be one of: ${allowedValues.join(", ")}.`);
  }
  return value;
}

function normalizeString(value, field) {
  if (typeof value !== "string" || !value.trim()) {
    throw new TypeError(`${field} must be a non-empty string.`);
  }
  return value.trim();
}

function normalizeTimestamp(value) {
  const date = value instanceof Date ? value : new Date(value);
  if (Number.isNaN(date.getTime())) {
    throw new TypeError("timestamp must be a valid date or ISO timestamp.");
  }
  return date.toISOString();
}
